import { INITIAL_CLIENTS_STORE } from '../../../clients/infrastructure/data/clients.mock';
import { VendorAssignedClient } from '../../domain/models/vendor.model';
import { VendorStore } from '../../domain/models/vendor-response.model';

const CLIENTS_BY_ID = new Map(INITIAL_CLIENTS_STORE.clients.map((client) => [client.id, client]));

function buildAssignedClient(clientId: string): VendorAssignedClient {
  const client = CLIENTS_BY_ID.get(clientId);

  if (!client) {
    throw new Error(`No se encontró el cliente ${clientId} para poblar vendedores mock.`);
  }

  return {
    clientId: client.id,
    idCliente: client.idCliente,
    nombre: client.nombre,
    zona: client.zona ?? '',
    ciudadNombre: client.ciudadNombre ?? null,
  };
}

